class Solution:
    def similarPairs(self, words):
        n = len(words)
        count = 0
        sets = [frozenset(w) for w in words]
        for i in range(n):
            for j in range(i + 1, n):
                if sets[i] == sets[j]:
                    count += 1
        return count

