var similarPairs = function(words) {
    const groups = new Map();
    for (const w of words) {
        const letters = new Set(w);
        const key = Array.from(letters).sort().join('');
        groups.set(key, (groups.get(key) || 0) + 1);
    }
    let total = 0;
    for (const c of groups.values()) {
        total += (c * (c - 1)) / 2;
    }
    return total;
};
